def transform(primary):
    h,w=grid.shape
    g=grid.copy()
    # conversion
    conversion=set()
    for r in range(h):
        for c in range(w):
            v=g[r,c]
            if v!=0 and v!=primary:
                for dr,dc in [(1,0),(-1,0),(0,1),(0,-1)]:
                    nr,nc=r+dr,c+dc
                    if 0<=nr<h and 0<=nc<w and g[nr,nc]==primary:
                        conversion.add((r,c))
                        break
    g2=g.copy()
    for r,c in conversion:
        g2[r,c]=primary
    for r in range(h):
        for c in range(w):
            if g2[r,c]!=primary:
                g2[r,c]=0
    g3=g2.copy()
    for r in range(h):
        for c in range(w):
            if g2[r,c]==primary:
                neigh=False
                for dr,dc in [(1,0),(-1,0),(0,1),(0,-1)]:
                    nr,nc=r+dr,c+dc
                    if 0<=nr<h and 0<=nc<w and g2[nr,nc]==primary:
                        neigh=True; break
                if not neigh:
                    g3[r,c]=0
    return g3
