def comp_properties(color):
    # largest component
    h,w=grid.shape
    visited=set()
    best=None
    for r in range(h):
        for c in range(w):
            if grid[r,c]==color and (r,c) not in visited:
                cells=[]
                stack=[(r,c)]
                visited.add((r,c))
                while stack:
                    rr,cc=stack.pop()
                    cells.append((rr,cc))
                    for dr,dc in [(1,0),(-1,0),(0,1),(0,-1)]:
                        nr,nc=rr+dr, cc+dc
                        if 0<=nr<h and 0<=nc<w and grid[nr,nc]==color and (nr,nc) not in visited:
                            visited.add((nr,nc))
                            stack.append((nr,nc))
                if best is None or len(cells)>len(best):
                    best=cells
    if best is None:
        return None
    rs=[r for r,_ in best]; cs=[c for _,c in best]
    return len(best), (min(rs),max(rs),min(cs),max(cs))
for col in [3,5,6,7]:
    print(col, comp_properties(col))

