def clusters(cells, diag=False):
    dirs=[(1,0),(-1,0),(0,1),(0,-1)]
    if diag:
        dirs += [(1,1),(1,-1),(-1,1),(-1,-1)]
    comp={}
    for c in cells:
        comp[c]=c
    def find(u):
        while comp[u]!=u:
            comp[u]=comp[comp[u]]
            u=comp[u]
        return u
    for a in cells:
        for d in dirs:
            b=(a[0]+d[0],a[1]+d[1])
            if b in comp:
                ra=find(a); rb=find(b)
                if ra!=rb:
                    comp[rb]=ra
    groups=defaultdict(list)
    for a in cells:
        groups[find(a)].append(a)
    return list(groups.values())
print(clusters(cells,diag=True))

