def hor_period(row):
    w=len(row)
    for p in range(1,w+1):
        if w%p==0:
            ok=True
            for i in range(p,w):
                if row[i]!=row[i%p]:
                    ok=False
                    break
            if ok:
                return p
print(hor_period(grid[0]))

def vert_period(mat):
    h=len(mat)
    for p in range(1,h+1):
        if h%p==0:
            ok=True
            for i in range(p,h):
                if mat[i]!=mat[i%p]:
                    ok=False
                    break
            if ok:
                return p
print(vert_period([tuple(row[:6]) for row in grid]))

