def is_hollow_square(r,c,size,color):
    if r+size>h or c+size>w: return False
    for i in range(size):
        for j in range(size):
            val=grid[r+i][c+j]
            border = (i==0 or j==0 or i==size-1 or j==size-1)
            if border:
                if val!=color:
                    return False
            else:
                if val!=0:
                    return False
    return True

