def is_square(grid,r,c,size,color,h,w):
    for i in range(size):
        for j in range(size):
            border = (i==0 or j==0 or i==size-1 or j==size-1)
            val=grid[r+i][c+j]
            if border:
                if val!=color: return False
            else:
                if val!=0: return False
    return True
