def border_uniform(grid,r,c,size,color):
    for i in range(size):
        if grid[r][c+i]!=color: return False
        if grid[r+size-1][c+i]!=color: return False
        if grid[r+i][c]!=color: return False
        if grid[r+i][c+size-1]!=color: return False
    return True
