def largest_rect(grid, color):
    H,W=grid.shape
    best=(0,0,None)
    for hsize in range(H,0,-1):
        for wsize in range(W,0,-1):
            pos=find_block(grid,color,hsize,wsize)
            if pos:
                if hsize*wsize>best[0]*best[1]:
                    best=(hsize,wsize,pos)
    return best
