def count_blocks(grid,color,hsize,wsize):
    H,W=grid.shape
    count=0
    pos=None
    for r in range(H-hsize+1):
        for c in range(W-wsize+1):
            if np.all(grid[r:r+hsize,c:c+wsize]==color):
                count+=1
                pos=(r,c)
    return count,pos
