def get_ver_runs(grid,color):
    lens=[]
    H,W=grid.shape
    for c in range(W):
        cnt=0
        for r in range(H):
            if grid[r,c]==color:
                cnt+=1
            else:
                if cnt>0:
                    lens.append((cnt,r-cnt,c))
                    cnt=0
        if cnt>0:
