def fill_holes(grid):
    n=len(grid); m=len(grid[0])
    from collections import deque
    visited=[[False]*m for _ in range(n)]
    q=deque()
    # enqueue border zeros
    for i in range(n):
        for j in range(m):
            if i in [0,n-1] or j in [0,m-1]:
                if grid[i][j]==0 and not visited[i][j]:
                    visited[i][j]=True
                    q.append((i,j))
    dirs=[(1,0),(-1,0),(0,1),(0,-1)]
    while q:
        i,j=q.popleft()
        for di,dj in dirs:
            ni,nj=i+di,j+dj
            if 0<=ni<n and 0<=nj<m and not visited[ni][nj] and grid[ni][nj]==0:
                visited[ni][nj]=True
                q.append((ni,nj))
    # fill holes
    res=[row[:] for row in grid]
    for i in range(n):
        for j in range(m):
            if grid[i][j]==0 and not visited[i][j]:
                res[i][j]=4
    return res
