from collections import deque
def reachable_to_edge(r,c,grid,block):
    rows=len(grid); cols=len(grid[0])
    visited=set()
    q=deque([(r,c)])
    visited.add((r,c))
    while q:
        rr,cc=q.popleft()
        if rr==0 or rr==rows-1 or cc==0 or cc==cols-1:
            return True
        for dr,dc in [(1,0),(-1,0),(0,1),(0,-1)]:
            nr=rr+dr; nc=cc+dc
            if 0<=nr<rows and 0<=nc<cols and (nr,nc) not in visited and grid[nr][nc]!=block:
                visited.add((nr,nc))
                q.append((nr,nc))
    return False
