def transform(grid):
    rows=len(grid); cols=len(grid[0])
    g=[row[:] for row in grid]
    # remove current 4s
    for r,c in blocks(g):
        for dr in [0,1]:
            for dc in [0,1]:
                g[r+dr][c+dc]=0
    # We'll move blocks
    placed=set()
    for r,c in blocks(grid): # original blocks list
        newc=(c+11)%cols
        # check if position valid
        def empty(rc):
            r0,c0=rc
            for dr in [0,1]:
                for dc in [0,1]:
                    nr=r0+dr; nc=c0+dc
                    if nc>=cols or g[nr][nc]!=0: return False
            return True
        if newc<c and (newc+1)==c:  # unnatural, ignore
            pass
        if empty((r,newc)):
            target=newc
        else:
            target=c
        for dr in [0,1]:
            for dc in [0,1]:
                g[r+dr][target+dc]=4
    return g

