def transform3(grid):
    rows=len(grid); cols=len(grid[0])
    newgrid=[row[:] for row in grid]
    for r,c in blocks(grid):
        for dr in [0,1]:
            for dc in [0,1]:
                newgrid[r+dr][c+dc]=0
    # order right-to-left
    all_blocks=sorted(blocks(grid), key=lambda x:-x[1])
    for r,c in all_blocks:
        if c==0 or c==cols-2: # touches border
            dest=c
        else:
            target = c+11 if c<10 else c-11
            def can_place(rc):
                r0,c0=rc
                if c0<0 or c0+1>=cols: return False
                for dr in [0,1]:
                    for dc in [0,1]:
                        if newgrid[r0+dr][c0+dc]!=0:
                            return False
                return True
            if can_place((r,target)):
                dest=target
            else:
                dest=c
        for dr in [0,1]:
            for dc in [0,1]:
                newgrid[r+dr][dest+dc]=4
    return newgrid
