def transform4(grid):
    rows=len(grid); cols=len(grid[0])
    newgrid=[row[:] for row in grid]
    for r,c in blocks(grid):
        for dr in [0,1]:
            for dc in [0,1]:
                newgrid[r+dr][c+dc]=0
    all_blocks=sorted(blocks(grid), key=lambda x:-x[1])
    left_exists=[False]*rows
    right_exists=[False]*rows
    for r,c in blocks(grid):
        if c<10:
            left_exists[r]=True
        else:
            right_exists[r]=True
    # Remember that block spans 2 rows but r is top, treat both rows
    for r,c in all_blocks:
        # Determine side presence in that row
        side_left=left_exists[r]
        side_right=right_exists[r]
        move_allowed=False
        if c<10 and not side_right:
            move_allowed=True
            target=c+11
        elif c>10 and not side_left:
            move_allowed=True
            target=c-11
        else:
            move_allowed=False
        def can_place(rc):
            r0,c0=rc
            if c0<0 or c0+1>=cols: return False
            for dr in [0,1]:
                for dc in [0,1]:
                    if newgrid[r0+dr][c0+dc]!=0:
                        return False
            return True
        dest=c
        if move_allowed and can_place((r,target)):
            dest=target
        for dr in [0,1]:
            for dc in [0,1]:
                newgrid[r+dr][dest+dc]=4
    return newgrid

