def bounding_contains_other(grid, blob):
    for r in range(blob['minr'], blob['maxr']+1):
        for c in range(blob['minc'], blob['maxc']+1):
            val=grid[r][c]
            if val!=0 and val!=blob['color']:
                return True
    return False
