def longest_segments(grid, color):
    H_lengths=[]
    for r in range(grid.shape[0]):
        length=0
        maxlen=0
        for c in range(grid.shape[1]):
            if grid[r,c]==color:
                length+=1
                maxlen=max(maxlen,length)
            else:
                length=0
        H_lengths.append(maxlen)
    V_lengths=[]
    for c in range(grid.shape[1]):
        length=0
        maxlen=0
        for r in range(grid.shape[0]):
            if grid[r,c]==color:
                length+=1
                maxlen=max(maxlen,length)
            else:
                length=0
        V_lengths.append(maxlen)
    Hmax=max(H_lengths)
    Vmax=max(V_lengths)
    return Hmax,Vmax,H_lengths,V_lengths
