                length=0
        if length>1:
            h+=1
    for c in range(grid.shape[1]):
        length=0
        for r in range(grid.shape[0]):
            if grid[r,c]==color:
                length+=1
            else:
                if length>1:
                    v+=1
                length=0
        if length>1:
            v+=1
    return h,v
